<?php
namespace App\Http\Controllers\Admin\Content;use App\Domain\Admin\Content\ContentAdminService;use App\Http\Controllers\Controller;use App\Http\Requests\Admin\Content\ZoneMonsterRequest;use App\Models\Monster;use App\Models\Zone;use InvalidArgumentException;
final class ZoneMonsterController extends Controller{public function store(ZoneMonsterRequest $request,Zone $zone,ContentAdminService $service){try{$monster=Monster::findOrFail($request->validated()['monster_id']);$service->saveZoneMonster($zone,$monster,$request->validated());return back()->with('status','Monstruo asignado.');}catch(InvalidArgumentException $e){return back()->withInput()->withErrors(['content'=>$e->getMessage()]);}}public function update(ZoneMonsterRequest $request,Zone $zone,Monster $monster,ContentAdminService $service){try{if((int)$request->validated()['monster_id']!==(int)$monster->id)throw new InvalidArgumentException('Monster mismatch.');$service->saveZoneMonster($zone,$monster,$request->validated());return back()->with('status','Asignación actualizada.');}catch(InvalidArgumentException $e){return back()->withInput()->withErrors(['content'=>$e->getMessage()]);}}public function destroy(Zone $zone,Monster $monster,ContentAdminService $service){$service->removeZoneMonster($zone,$monster);return back()->with('status','Monstruo retirado de la zona.');}}
